 {{Tlx|Inflation|''index''|''value''|''start_year''|5=r=''decimals''|6=fmt=eq}}
 {{Tlx|Inflation|''index''|''value''|''start_year''|5=r=''decimals''|6=fmt=eq|7=cursign=X}}

