| style="text-align:left;" | United States{{Inflation/fn|US}} || {{Inflation/US/startyear}} || {{Inflation/year|US}}
|-
! scope="row" | US-GDP
| style="text-align:left;" | United States [[GDP deflator]]{{Inflation/fn|US-GDP}} || {{Inflation/US-GDP/startyear}} || {{Inflation/year|US-GDP}}
|-
! scope="row" | ZAR
| style="text-align:left;" | South Africa{{Inflation/fn|ZAR}} || {{Inflation/ZAR/startyear}} || {{Inflation/year|ZAR}}
